mapper.select:
select user_id, password, name, email, address, phone
from tb_user
where user_id = #{user_id}
and password = #{password}

mapper.update:
update tb_user
set password = #{password}, name = #{name}, address = #{address}, phone = #{phone}, email = #{email}
